const q = $input.first().json.query || {};

const conditions = ['1=1'];

if (q.program_name) {
  const safe = q.program_name.toUpperCase().replace(/[^A-Z0-9-]/g, '');
  conditions.push(`cgs.program_name = '${safe}'`);
}

if (q.status) {
  const statuses = q.status.split(',').map(s => `'${s.trim()}'`).join(',');
  conditions.push(`cgs.status IN (${statuses})`);
}

if (q.scope) {
  const safe = q.scope.toLowerCase().replace(/[^a-z]/g, '');
  conditions.push(`cgs.scope = '${safe}'`);
}

if (q.content_type) {
  const safe = q.content_type.toLowerCase().replace(/[^a-z_]/g, '');
  conditions.push(`cgs.content_type = '${safe}'`);
}

const sql = `
SELECT
  cgs.id,
  cgs.content_type,
  cgs.scope,
  cgs.program_name,
  cgs.resource_key,
  cgs.status,
  cgs.generated_at,
  cgs.output_table,
  cgs.output_id,
  cgs.error_message,
  cgs.retry_count,
  cgs.updated_at
FROM cobol_analysis.content_generation_status cgs
WHERE ${conditions.join('\n  AND ')}
ORDER BY cgs.scope DESC, cgs.program_name, cgs.content_type
`;

return { json: { sql } };

const items = $input.all();

// Totales por status
const totals = { pending: 0, stale: 0, completed: 0, in_progress: 0, failed: 0 };
for (const item of items) {
  const s = item.json.status;
  if (totals[s] !== undefined) totals[s]++;
}

// Agrupa por programa para scope=program, plano para scope=system
const byProgram = {};
const systemItems = [];

for (const item of items) {
  const row = item.json;

  if (row.scope === 'program') {
    const key = row.program_name;
    if (!byProgram[key]) byProgram[key] = { program_name: key, scope: 'program', content: {} };
    byProgram[key].content[row.content_type] = {
      id:           row.id,
      status:       row.status,
      generated_at: row.generated_at,
      output_id:    row.output_id,
      output_table: row.output_table,
      error_message:row.error_message,
      retry_count:  row.retry_count,
      updated_at:   row.updated_at
    };
  } else {
    systemItems.push({
      id:           row.id,
      content_type: row.content_type,
      scope:        row.scope,
      resource_key: row.resource_key,
      status:       row.status,
      generated_at: row.generated_at,
      output_id:    row.output_id,
      error_message:row.error_message,
      updated_at:   row.updated_at
    });
  }
}

return {
  json: {
    success:  true,
    total:    items.length,
    totals,
    programs: Object.values(byProgram),
    system:   systemItems
  }
};
